@Configuration
class JooqConfiguration {
    @Bean
    fun dslContext(dataSource: DataSource): DSLContext {
        return DSL.using(dataSource, SQLDialect.POSTGRES)
    }
}

jooq {
    configurations {
        create("main") {
            generator.apply {
                name = "org.jooq.codegen.KotlinGenerator"
                database.apply {
                    includes = ".*_view"  // Only projection tables
                }
            }
        }
    }
}
